#include<bits/stdc++.h>
using namespace std;

char a[10005],b[10005];

int main()
{
	scanf("%s",a);
	scanf("%s",b);
	if(strstr(a,b))
	{
		printf("%s",b);
		printf(" is substring of ");
		printf("%s",a);
		return 0;
	}
	else if(strstr(b,a))
	{
		printf("%s",a);
		printf(" is substring of ");
		printf("%s",b);
		return 0;
	}
	printf("No substring");
	return 0;
}
